import{_ as s,o as n,c as p,ag as l}from"./chunks/framework.-Wrcbzkw.js";const u=JSON.parse('{"title":"TOT (Tree of Thought) 思维树","description":"","frontmatter":{},"headers":[],"relativePath":"LLM/Prompt Engineering/05_tot_思维树.md","filePath":"LLM/Prompt Engineering/05_tot_思维树.md","lastUpdated":1778838722000}'),e={name:"LLM/Prompt Engineering/05_tot_思维树.md"};function t(i,a,c,o,r,d){return n(),p("div",null,[...a[0]||(a[0]=[l(`<h1 id="tot-tree-of-thought-思维树" tabindex="-1">TOT (Tree of Thought) 思维树 <a class="header-anchor" href="#tot-tree-of-thought-思维树" aria-label="Permalink to &quot;TOT (Tree of Thought) 思维树&quot;">​</a></h1><p>探索多条思考路径，选择最优解。</p><hr><h2 id="示例一-职业选择分析" tabindex="-1">示例一：职业选择分析 <a class="header-anchor" href="#示例一-职业选择分析" aria-label="Permalink to &quot;示例一：职业选择分析&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问题：我应该选择哪个工作offer？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>让我们从多个维度探索：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>路径A - 大厂工作：</span></span>
<span class="line"><span>优势：薪资高、品牌背书、技术成熟</span></span>
<span class="line"><span>劣势：竞争激烈、晋升慢、可能成为螺丝钉</span></span>
<span class="line"><span>适合人群：追求稳定、需要背书</span></span>
<span class="line"><span></span></span>
<span class="line"><span>路径B - 创业公司：</span></span>
<span class="line"><span>优势：股权机会、成长快、能影响产品</span></span>
<span class="line"><span>劣势：风险高、资源少、可能倒闭</span></span>
<span class="line"><span>适合人群：冒险精神、执行力强</span></span>
<span class="line"><span></span></span>
<span class="line"><span>路径C - 外企：</span></span>
<span class="line"><span>优势：work-life balance、文化开放</span></span>
<span class="line"><span>劣势：天花板明显、语言要求</span></span>
<span class="line"><span>适合人群：注重生活品质</span></span>
<span class="line"><span></span></span>
<span class="line"><span>综合评估：根据你的优先级（薪资/成长/稳定/生活）选择</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果最看重成长：选B</span></span>
<span class="line"><span>如果最看重稳定：选A</span></span>
<span class="line"><span>如果最看重生活：选C</span></span></code></pre></div><hr><h2 id="示例二-营销方案设计" tabindex="-1">示例二：营销方案设计 <a class="header-anchor" href="#示例二-营销方案设计" aria-label="Permalink to &quot;示例二：营销方案设计&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问题：为一款新产品设计营销方案</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请探索3种不同策略：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>策略A - 社交媒体营销：</span></span>
<span class="line"><span>- 平台：抖音、小红书</span></span>
<span class="line"><span>- 内容：短视频种草、KOL合作</span></span>
<span class="line"><span>- 预算：中等</span></span>
<span class="line"><span>- 周期：持续进行</span></span>
<span class="line"><span>- 风险：竞争激烈</span></span>
<span class="line"><span></span></span>
<span class="line"><span>策略B - 搜索引擎广告：</span></span>
<span class="line"><span>- 平台：百度、360</span></span>
<span class="line"><span>- 内容：关键词竞价</span></span>
<span class="line"><span>- 预算：较高</span></span>
<span class="line"><span>- 周期：持续投入</span></span>
<span class="line"><span>- 风险：成本上升</span></span>
<span class="line"><span></span></span>
<span class="line"><span>策略C - 私域流量运营：</span></span>
<span class="line"><span>- 平台：微信群、公众号</span></span>
<span class="line"><span>- 内容：社群运营、裂变活动</span></span>
<span class="line"><span>- 预算：较低</span></span>
<span class="line"><span>- 周期：长期积累</span></span>
<span class="line"><span>- 风险：起量慢</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请根据产品特点和预算，选择最优方案</span></span></code></pre></div><hr><h2 id="示例三-代码架构选择" tabindex="-1">示例三：代码架构选择 <a class="header-anchor" href="#示例三-代码架构选择" aria-label="Permalink to &quot;示例三：代码架构选择&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问题：为中型电商系统选择后端架构</span></span>
<span class="line"><span></span></span>
<span class="line"><span>探索3种方案：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方案A - 单体架构：</span></span>
<span class="line"><span>优点：简单、开发快、部署简单</span></span>
<span class="line"><span>缺点：扩展性差、无法应对高并发</span></span>
<span class="line"><span>适用：初创公司、用户量&lt;10万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方案B - 微服务架构：</span></span>
<span class="line"><span>优点：扩展性强、技术灵活、团队独立</span></span>
<span class="line"><span>缺点：复杂度高、运维成本高</span></span>
<span class="line"><span>适用：大型团队、用户量&gt;100万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>方案C - 模块化单体：</span></span>
<span class="line"><span>优点：平衡性好、可逐步拆分</span></span>
<span class="line"><span>缺点：不如微服务灵活</span></span>
<span class="line"><span>适用：中型团队、用户量10-100万</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请根据团队规模和预期用户量给出建议</span></span></code></pre></div><hr><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>效果</th></tr></thead><tbody><tr><td>决策分析</td><td>多选项对比，避免武断</td></tr><tr><td>方案设计</td><td>探索不同解决路径</td></tr><tr><td>商业分析</td><td>多角度评估风险机会</td></tr><tr><td>创意生成</td><td>产生更多可能性</td></tr></tbody></table><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li>不只找一条路，探索多条分支</li><li>每条路径分析利弊</li><li>最终给出推荐或让用户选择</li><li>适合复杂决策场景</li></ul><h2 id="vs-cot-的区别" tabindex="-1">vs COT 的区别 <a class="header-anchor" href="#vs-cot-的区别" aria-label="Permalink to &quot;vs COT 的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方法</th><th>思维</th></tr></thead><tbody><tr><td>COT</td><td>线性思考，一步接一步</td></tr><tr><td>TOT</td><td>树状探索，多路径并行</td></tr></tbody></table>`,18)])])}const b=s(e,[["render",t]]);export{u as __pageData,b as default};
